function countCRM(msgs) {
  let saveCRM = 0, createTask = 0, draftFollowup = 0;
  for (const m of msgs) {
    const mtype = m.message_type || '';
    const content = (m.content || '').toLowerCase();
    let meta = {};
    if (m.metadata) {
      try { meta = typeof m.metadata === 'string' ? JSON.parse(m.metadata) : m.metadata; } catch(e) {}
    }
    // Auto-saved recaps count as CRM saves
    if (mtype === 'save_to_crm' || mtype === 'meeting_recap'
        || content.includes('saved to crm') || content.includes('recap saved')
        || content.includes('save_recap')) saveCRM++;
    // Task creation
    if (mtype === 'create_task' || content.includes('task created')
        || content.includes('create_task') || content.includes('tasks created')) createTask++;
    // Draft follow-up
    if (mtype === 'followup_draft' || content.includes('draft follow-up')
        || content.includes('followup_draft') || content.includes('drafted a follow-up')) draftFollowup++;
  }
  return { saveCRM, createTask, draftFollowup, total: saveCRM + createTask + draftFollowup };
}

