  'meet': /^(meet|prep|meeting brief|meeting prep)\b/i,
  'insights': /^insights?\b/i,
  'presentation': /^(presentation|slide|slides|deck)\b/i,
  'stakeholders': /^stakeholders?\b/i,
  'silence': /^silence\b/i,
  'icp': /^icp\b/i,
  'tasks': /^tasks?\b/i,
  'bbr': /^(bbr|pbr)\b/i,
