  const outbound = allMsgs.filter(m => m.direction === 'outbound');
  for (const m of outbound) {
    const skill = messageTypeToSkill[m.message_type];
    if (skill) counts[skill] = (counts[skill] || 0) + 1;
  }
  return counts;
}

